150.     private static string? ApplyRules(List<InflectionEntry> rules, string word)
151.     {
152.         for (var i = rules.Count - 1; i >= 0; i--)
153.         {
154.             var result = rules[i].Apply(word);
155.             if (result != null)
156.             {
157.                 return result;
158.             }
159.         }
160. 
161.         return null;
162.     }
163. 
164.     /// <summary>
165.     /// Internal rule entry holding a compiled regex and replacement pattern.
166.     /// </summary>
167.     private class InflectionEntry
168.     {
169.         private readonly Regex _regex;
170.         private readonly string _replacement;
171. 
172.         public InflectionEntry(string pattern, string replacement)
173.         {
174.             // Anti-pattern: compiled regex per rule — with 40+ rules this is
175.             // 40+ compiled regexes at startup, consuming 100-500ms
176.             _regex = new Regex(pattern, RegexOptions.IgnoreCase | RegexOptions.Compiled);
177.             _replacement = replacement;
178.         }
179. 
180.         public string? Apply(string word)
181.         {
182.             if (!_regex.IsMatch(word))
183.             {
184.                 return null;
185.             }
186. 
187.             return _regex.Replace(word, _replacement);
188.         }
189.     }
190. }
