3. namespace Textualizer.Inflections;
4. 
5. /// <summary>
6. /// Manages a set of pluralization and singularization rules, along with uncountable
7. /// and irregular word lists, for transforming English words between their plural
8. /// and singular forms.
9. /// </summary>
10. public class WordVocabulary
11. {
12.     private readonly List<InflectionEntry> _plurals = [];
13.     private readonly List<InflectionEntry> _singulars = [];
14. 
15.     private readonly HashSet<string> _uncountables = new(StringComparer.OrdinalIgnoreCase);
16. 
17.     private readonly Dictionary<string, string> _irregularPlurals =
18.         new(StringComparer.OrdinalIgnoreCase);
19.     private readonly Dictionary<string, string> _irregularSingulars =
20.         new(StringComparer.OrdinalIgnoreCase);
21. 
22.     /// <summary>
23.     /// Gets the number of pluralization rules currently registered.
24.     /// </summary>
25.     public int PluralRuleCount => _plurals.Count;
26. 
27.     /// <summary>
28.     /// Gets the number of singularization rules currently registered.
29.     /// </summary>
30.     public int SingularRuleCount => _singulars.Count;
31. 
32.     /// <summary>
33.     /// Gets the number of uncountable words registered.
34.     /// </summary>
35.     public int UncountableCount => _uncountables.Count;
36. 
37.     /// <summary>
38.     /// Adds a pluralization rule with the given regex pattern and replacement.
39.     /// </summary>
40.     /// <param name="pattern">A regex pattern that matches the singular form.</param>
41.     /// <param name="replacement">The replacement string for generating the plural form.</param>
42.     public void AddPlural(string pattern, string replacement)
43.     {
44.         _uncountables.Remove(pattern);
45.         _uncountables.Remove(replacement);
46.         _plurals.Add(new InflectionEntry(pattern, replacement));
47.     }
48. 
49.     /// <summary>
50.     /// Adds a singularization rule with the given regex pattern and replacement.
51.     /// </summary>
52.     /// <param name="pattern">A regex pattern that matches the plural form.</param>
53.     /// <param name="replacement">The replacement string for generating the singular form.</param>
54.     public void AddSingular(string pattern, string replacement)
55.     {
56.         _uncountables.Remove(pattern);
57.         _uncountables.Remove(replacement);
58.         _singulars.Add(new InflectionEntry(pattern, replacement));
59.     }
60. 
61.     /// <summary>
62.     /// Registers an irregular plural/singular pair (e.g., "person" / "people").
63.     /// </summary>
64.     /// <param name="singular">The singular form of the word.</param>
65.     /// <param name="plural">The plural form of the word.</param>
66.     public void AddIrregular(string singular, string plural)
67.     {
68.         ArgumentException.ThrowIfNullOrWhiteSpace(singular);
69.         ArgumentException.ThrowIfNullOrWhiteSpace(plural);
70. 
71.         _uncountables.Remove(singular);
72.         _uncountables.Remove(plural);
73.         _irregularPlurals[singular] = plural;
74.         _irregularSingulars[plural] = singular;
75.     }
76. 
77.     /// <summary>
78.     /// Marks a word as uncountable (e.g., "equipment", "information", "rice").
79.     /// Uncountable words are returned unchanged by both pluralization and singularization.
80.     /// </summary>
81.     /// <param name="word">The uncountable word to register.</param>
82.     public void AddUncountable(string word)
83.     {
84.         ArgumentException.ThrowIfNullOrWhiteSpace(word);
85.         _uncountables.Add(word.Trim());
86.     }
87. 
88.     /// <summary>
89.     /// Returns the plural form of the given word using registered rules.
90.     /// </summary>
91.     /// <param name="word">The word to pluralize.</param>
92.     /// <returns>The plural form of the word.</returns>
93.     public string Pluralize(string word)
94.     {
95.         if (string.IsNullOrWhiteSpace(word))
96.         {
97.             return word;
98.         }
99. 
100.         if (_uncountables.Contains(word))
101.         {
102.             return word;
103.         }
104. 
105.         if (_irregularPlurals.TryGetValue(word, out var irregularPlural))
106.         {
107.             return irregularPlural;
108.         }
109. 
110.         return ApplyRules(_plurals, word) ?? word;
111.     }
112. 
113.     /// <summary>
114.     /// Returns the singular form of the given word using registered rules.
115.     /// </summary>
116.     /// <param name="word">The word to singularize.</param>
117.     /// <returns>The singular form of the word.</returns>
118.     public string Singularize(string word)
119.     {
120.         if (string.IsNullOrWhiteSpace(word))
121.         {
122.             return word;
123.         }
124. 
125.         if (_uncountables.Contains(word))
126.         {
127.             return word;
128.         }
129. 
130.         if (_irregularSingulars.TryGetValue(word, out var irregularSingular))
131.         {
132.             return irregularSingular;
133.         }
134. 
135.         return ApplyRules(_singulars, word) ?? word;
136.     }
137. 
138.     /// <summary>
139.     /// Checks whether a word is registered as uncountable.
140.     /// </summary>
141.     /// <param name="word">The word to check.</param>
142.     /// <returns>true if the word is uncountable; otherwise, false.</returns>
143.     public bool IsUncountable(string word) =>
144.         !string.IsNullOrWhiteSpace(word) && _uncountables.Contains(word.Trim());
145. 
146.     private static string? ApplyRules(List<InflectionEntry> rules, string word)
147.     {
148.         for (var i = rules.Count - 1; i >= 0; i--)
149.         {
150.             var result = rules[i].Apply(word);
151.             if (result != null)
152.             {
153.                 return result;
154.             }
155.         }
156. 
157.         return null;
158.     }
159. 
160.     /// <summary>
161.     /// Internal rule entry holding a compiled regex and replacement pattern.
162.     /// </summary>
163.     private class InflectionEntry
164.     {
165.         private readonly Regex _regex;
166.         private readonly string _replacement;
167. 
168.         public InflectionEntry(string pattern, string replacement)
169.         {
170.             _regex = new Regex(pattern, RegexOptions.IgnoreCase, TimeSpan.FromMilliseconds(250));
171.             _replacement = replacement;
172.         }
173. 
174.         public string? Apply(string word)
175.         {
176.             var result = _regex.Replace(word, _replacement, count: 1);
177.             return string.Equals(result, word, StringComparison.Ordinal) ? null : result;
178.         }
179.     }
180. }
181. 
